const raw = $json.output || $json.text || $json;

let parsed;

try {
  if (typeof raw === 'string') {
    parsed = JSON.parse(raw);
  } else {
    parsed = raw;
  }
} catch (error) {
  parsed = {
    intent: 'unclear',
    service: 'unknown',
    confidence: 0,
    language: 'unknown',
    extracted_fields: {},
    needs_human: false
  };
}

return [
  {
    json: {
      ...$json,
      intent: parsed.intent || 'unclear',
      service: parsed.service || 'unknown',
      confidence: parsed.confidence || 0,
      language: parsed.language || 'unknown',
      extracted_fields: parsed.extracted_fields || {},
      needs_human: parsed.needs_human || false
    }
  }
];

const item = $input.first();
const input = item.json || {};
const binary = item.binary || {};

const binaryKeys = Object.keys(binary || {});
const firstBinaryKey = binaryKeys[0] || '';

let attachmentBase64 = '';
let attachmentBinaryKey = '';
let fileName = '';
let fileExtension = '';
let mimeType = '';
let fileSize = '';

if (firstBinaryKey && binary[firstBinaryKey]) {
  const file = binary[firstBinaryKey];

  const buffer = await this.helpers.getBinaryDataBuffer(0, firstBinaryKey);
  attachmentBase64 = buffer.toString('base64');

  attachmentBinaryKey = firstBinaryKey;
  fileName = file.fileName || file.filename || '';
  mimeType = file.mimeType || file.mimetype || '';
  fileSize = file.fileSize || file.file_size || '';

  if (fileName && fileName.includes('.')) {
    fileExtension = fileName.split('.').pop();
  }
}

const hasAttachment = !!attachmentBase64;

return [
  {
    json: {
      ...input,

      attachment_base64: attachmentBase64,
      attachment_base64_available: hasAttachment,

      has_attachment: hasAttachment,
      attachment_count: hasAttachment ? 1 : 0,

      attachment_file_name: fileName,
      attachment_file_extension: fileExtension,
      attachment_mime_type: mimeType,
      attachment_file_size: fileSize,

      attachment_binary_key: attachmentBinaryKey,
      attachment_info: hasAttachment
        ? `${fileName} | ${mimeType} | ${fileSize}`
        : ''
    },
    binary
  }
];

const input = $input.first().json || {};
const msg = String(input.message || '').trim().toLowerCase();

function parseSession(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try {
    return JSON.parse(raw);
  } catch (e) {
    return {};
  }
}

let data = parseSession(input.session_data);

let reply = '';
let language = input.language || data.language || '';
let currentStage = input.current_stage || data.current_stage || 'language_selection';

/**
 * STAGE 1: Language selection
 */
if (currentStage === 'language_selection') {
  if (msg === '1') {
    language = 'English';
  } else if (msg === '2') {
    language = 'Tamil';
  } else if (msg === '3') {
    language = 'Tanglish';
  } else {
    reply = [
      'Welcome to LANDOC Marriage Registration Service Assistant. I’ll help you with your service request.',
      '',
      'Please choose your preferred language:',
      '1. English',
      '2. தமிழ்',
      '3. Tanglish'
    ].join('\n');

    data.current_stage = 'language_selection';

    return [{
      json: {
        ...input,
        active_service: '',
        current_stage: 'language_selection',
        language: '',
        session_data: JSON.stringify(data),
        reply,
        output: reply,
        last_reply: reply,
        should_call_marriage_workflow: false,
        service_menu_handled: true
      }
    }];
  }

  data.language = language;
  data.current_stage = 'main_menu';
  data.active_service = '';

  reply = [
    'Please choose an option:',
    '',
    '1️⃣ Service Request Status',
    '2️⃣ Requesting for New Service',
    '',
    'Reply with the option number.'
  ].join('\n');

  return [{
    json: {
      ...input,
      active_service: '',
      current_stage: 'main_menu',
      language,
      session_data: JSON.stringify(data),
      reply,
      output: reply,
      last_reply: reply,
      should_call_marriage_workflow: false,
      service_menu_handled: true
    }
  }];
}

/**
 * STAGE 2: Main menu
 */
if (currentStage === 'main_menu') {
  if (msg === '1') {
    data.main_menu_selected = 'service_status';
    data.current_stage = 'ticket_status_reference';
    data.active_service = '';

    reply = [
      'Please share your service request number or registered mobile number to check the status.'
    ].join('\n');

    return [{
      json: {
        ...input,
        active_service: '',
        current_stage: 'ticket_status_reference',
        language: language || data.language || 'English',
        session_data: JSON.stringify(data),
        reply,
        output: reply,
        last_reply: reply,
        ticket_status_requested: true,
        ready_to_fetch_ticket_status: false,
        should_call_marriage_workflow: false,
        service_menu_handled: true
      }
    }];
  }

  if (msg === '2') {
    data.main_menu_selected = 'new_service';
    data.current_stage = 'service_selection';
    data.active_service = '';

    reply = [
      'Please select the service you need:',
      '',
      '1️⃣ Marriage Registration',
      '',
      'Reply with the option number.'
    ].join('\n');

    return [{
      json: {
        ...input,
        active_service: '',
        current_stage: 'service_selection',
        language: language || data.language || 'English',
        session_data: JSON.stringify(data),
        reply,
        output: reply,
        last_reply: reply,
        should_call_marriage_workflow: false,
        service_menu_handled: true
      }
    }];
  }

  reply = [
    'Please choose a valid option:',
    '',
    '1️⃣ Service Request Status',
    '2️⃣ Requesting for New Service'
  ].join('\n');

  return [{
    json: {
      ...input,
      active_service: '',
      current_stage: 'main_menu',
      language: language || data.language || 'English',
      session_data: JSON.stringify(data),
      reply,
      output: reply,
      last_reply: reply,
      should_call_marriage_workflow: false,
      service_menu_handled: true
    }
  }];
}

/**
 * STAGE 3: Service selection
 */
if (currentStage === 'service_selection') {
  if (msg === '1') {
    data.main_menu_selected = 'new_service';
    data.active_service = 'marriage_registration';
    data.intent = 'marriage_registration';
    data.current_stage = 'start';
    data.language = language || data.language || 'English';

    return [{
      json: {
        ...input,
        active_service: 'marriage_registration',
        current_stage: 'start',
        language: data.language,
        session_data: JSON.stringify(data),
        reply: '',
        output: '',
        last_reply: '',
        intent: 'marriage_registration',
        should_call_marriage_workflow: true,
        service_menu_handled: true
      }
    }];
  }

  reply = [
    'Please select a valid service option:',
    '',
    '1️⃣ Marriage Registration'
  ].join('\n');

  data.current_stage = 'service_selection';
  data.active_service = '';

  return [{
    json: {
      ...input,
      active_service: '',
      current_stage: 'service_selection',
      language: language || data.language || 'English',
      session_data: JSON.stringify(data),
      reply,
      output: reply,
      last_reply: reply,
      should_call_marriage_workflow: false,
      service_menu_handled: true
    }
  }];
}

/**
 * STAGE 4: Ticket status reference
 * For now only collect reference/mobile and let your ticket status workflow handle it later.
 */
if (currentStage === 'ticket_status_reference') {
  data.ticket_status_requested = true;
  data.ticket_reference = msg;
  data.current_stage = 'ticket_status_reference';
  data.active_service = '';

  reply = [
    'Thank you. Please wait while we check your service request status.'
  ].join('\n');

  return [{
    json: {
      ...input,
      active_service: '',
      current_stage: 'ticket_status_reference',
      language: language || data.language || 'English',
      session_data: JSON.stringify(data),
      reply,
      output: reply,
      last_reply: reply,
      ticket_status_requested: true,
      ready_to_fetch_ticket_status: true,
      should_call_marriage_workflow: false,
      service_menu_handled: true
    }
  }];
}

return [{
  json: {
    ...input,
    should_call_marriage_workflow: false,
    service_menu_handled: false
  }
}];
